function useInView(ref,th=0.15){const[v,s]=useState(false);useEffect(()=>{const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)s(true)},{threshold:th});if(ref.current)o.observe(ref.current);return()=>o.disconnect()},[ref,th]);return v;}

function FadeIn({children,delay=0}){
  const ref=useRef();const v=useInView(ref);
  return <div ref={ref} style={{opacity:v?1:0,transform:v?"translateY(0)":"translateY(28px)",transition:`opacity 0.7s ease ${delay}s,transform 0.7s ease ${delay}s`}}>{children}</div>;
}

